#### **4. 业务逻辑中访问用户身份信息**

在基于 WebFlux 的控制器中，我们可以直接通过 `ReactiveSecurityContextHolder` 获取用户的身份信息。

示例如下：

```java
import org.springframework.security.core.context.ReactiveSecurityContextHolder;
import org.springframework.security.oauth2.core.OAuth2AuthenticatedPrincipal;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;
import reactor.core.publisher.Mono;

import java.util.Map;

@RestController
public class UserController {

    @GetMapping("/me")
    public Mono<Map<String, Object>> getUserDetails() {
        return ReactiveSecurityContextHolder.getContext()
            .map(securityContext -> {
                OAuth2AuthenticatedPrincipal principal = (OAuth2AuthenticatedPrincipal) securityContext.getAuthentication().getPrincipal();
                return Map.of(
                    "username", principal.getName(), // 用户名
                    "attributes", principal.getAttributes() // JWT 解码后的所有声明
                );
            });
